  ('locality-0c700c30-moex-00055', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '假設有一商品其供給彈性之絕對值大於需求彈性之絕對值，若政府決定對該項商品課稅，則實際 稅負主要由何者承受？', '["消費者", "生產者", "消費者和生產者承受比重相同", "取決於稅負是向消費者或生產者徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00056', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '假設消費者的效用函數為U(X,Y)=X+Y，其中X和Y為財貨的消費數量，下列敘述何者正確？', '["此效用函數所代表的偏好不滿足完整性", "此效用函數所代表的偏好不滿足遞移性", "此效用函數所代表的偏好不滿足越多越好的特性", "此效用函數所代表的偏好不滿足嚴格凸性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00057', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '某一廠商的生產函數為q=L0.5K1.5，其中q為生產量、L為勞動要素投入量、而K則為資本要素 投入量。有關此生產函數邊際產量（marginalproduct）之敘述，下列何者正確？', '["勞動的邊際產量遞增，資本的邊際產量遞增", "勞動的邊際產量遞增，資本的邊際產量遞減", "勞動的邊際產量遞減，資本的邊際產量遞增", "勞動的邊際產量遞減，資本的邊際產量遞減"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00058', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '短期邊際成本終會隨著產量增加而上升的原因為何？', '["從市場購入更多的變動投入需要負擔更高的價格", "產量增加需要使用更多的變動投入", "產量增加時每單位產出所分攤之固定成本也會增加", "變動投入具有邊際報酬遞減的特性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00059', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '有關獨占性競爭市場與完全競爭市場均衡的結果，下列敘述何者錯誤？', '["在短期均衡下，完全競爭廠商為價格的接受者，而獨占性競爭廠商可由MR=MC的條件下決定 產量與價格", "長期均衡時，兩者皆會在最有效率的規模下生產，也就是在平均總成本最低點生產", "長期均衡時，完全競爭廠商的價格會等於邊際成本，而獨占性競爭廠商的價格會高於邊際成本", "在短期均衡下，完全競爭或獨占性競爭廠商都可能有正或負的利潤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00060', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '在一個寡占市場中，僅有兩家廠商。此兩家廠商有相同的成本函數，TC=3Q，其中TC為總成本， Q為產量。市場需求函數則為Q=10-P，其中Q為消費量，P為價格。如果這兩家廠商競爭的模 式是所謂的價格競爭模型（Bertrandcompetition），市場的均衡價格和數量為何？', '["均衡價格為$3，均衡數量為7", "均衡價格為$3，均衡數量為14", "均衡價格為$7，均衡數量為3", "均衡價格為$7，均衡數量為6 31860 50550"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
  ('locality-0c700c30-moex-00061', 'locality-0c700c30', 'locality-0c700c30-moex-113-d3ff7f6b', 'sub-locality-0c700c30-03', NULL, 'single_choice', '下列何種情況下適合使用Stackelberg模型而非Cournot模型來分析廠商之間的互動？', '["廠商依照先來後到制訂產量", "當市場上有超過2家以上的廠商", "所有的廠商同時進入市場制訂產量", "廠商依照先來後到制訂價格"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:13+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "314", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "統計"}'::jsonb, NULL),
